import { createStore } from 'vuex'
import { authService } from '@/services/authService'
import { STORAGE_KEYS, clearAuthStorage } from '@/utils/storage'
import profile from '@/api/profile'
import { auth } from '@/api/auth'
import axios from 'axios'
import router from '../router'

export default createStore({
  state: {
    isAuthenticated: false,
    userInfo: null,
    basicInfo: null,
    completeness: null,
    token: null,
    refreshToken: null
  },

  mutations: {
    SET_AUTH(state, isAuthenticated) {
      state.isAuthenticated = isAuthenticated
    },

    SET_USER_INFO(state, userInfo) {
      state.userInfo = userInfo
    },

    SET_BASIC_INFO(state, basicInfo) {
      state.basicInfo = {
        ...state.basicInfo,
        ...basicInfo
      }
    },

    SET_COMPLETENESS(state, completeness) {
      state.completeness = completeness
    },

    SET_AVATAR_UPDATE_TIME(state, timestamp) {
      state.avatarUpdateTime = timestamp
    },

    SET_TOKEN(state, token) {
      state.token = token
      state.isAuthenticated = !!token
    },

    SET_REFRESH_TOKEN(state, refreshToken) {
      state.refreshToken = refreshToken
    },

    SET_USER(state, user) {
      state.userInfo = user
    },

    SET_LOGGED_IN(state, status) {
      state.isAuthenticated = status
    },

    SET_AUTHENTICATED(state, isAuthenticated) {
      state.isAuthenticated = isAuthenticated
    }
  },

  getters: {
    userAvatar: state => {
      return state.basicInfo?.avatar || '/default-avatar.png'
    },

    userName: state => {
      return state.basicInfo?.name || state.userInfo?.username || '未设置昵称'
    },

    userPhone: state => {
      return state.basicInfo?.phone || state.userInfo?.phone
    },

    profileCompleteness: state => {
      return state.completeness || 0
    }
  },

  actions: {
    async checkAuth({ commit, dispatch }) {
      const token = localStorage.getItem(STORAGE_KEYS.TOKEN)
      const refreshToken = localStorage.getItem(STORAGE_KEYS.REFRESH_TOKEN)
      const userInfo = localStorage.getItem(STORAGE_KEYS.USER_INFO)
      const tokenExpires = localStorage.getItem(STORAGE_KEYS.TOKEN_EXPIRES)
      const refreshExpires = localStorage.getItem(STORAGE_KEYS.REFRESH_TOKEN_EXPIRES)

      const now = Date.now()

      if (token && refreshToken) {
        // 检查 token 是否过期
        if (tokenExpires && parseInt(tokenExpires) > now) {
          // token 未过期，直接使用
          commit('SET_TOKEN', token)
          commit('SET_REFRESH_TOKEN', refreshToken)
          if (userInfo) {
            commit('SET_USER', JSON.parse(userInfo))
          }
          commit('SET_LOGGED_IN', true)
          await dispatch('fetchUserInfo')
          return true
        } else if (refreshExpires && parseInt(refreshExpires) > now) {
          // token 过期但 refresh token 未过期，尝试刷新
          const refreshSuccess = await dispatch('refreshToken')
          if (refreshSuccess) {
            if (userInfo) {
              commit('SET_USER', JSON.parse(userInfo))
            }
            commit('SET_LOGGED_IN', true)
            await dispatch('fetchUserInfo')
            return true
          }
        }
      }

      return false
    },

    async fetchUserInfo({ commit }) {
      try {
        const response = await profile.getBasicInfo()
        console.log('API Response:', response.data)

        if (response.data?.code === 200) {
          const { user, basic_info } = response.data.data
          console.log('Extracted Data:', { user, basic_info })

          if (user) {
            commit('SET_USER_INFO', user)
          }
          if (basic_info) {
            commit('SET_BASIC_INFO', basic_info)
          }
          return response.data.data
        }
      } catch (error) {
        console.error('Failed to get user info:', error)
        // 移除401处理逻辑，只记录错误
        console.error('Failed to get user info:', error)
        throw error
      }
    },

    async updateBasicInfo({ commit }, { type, data }) {
      try {
        let response
        if (type === 'avatar') {
          response = await profile.uploadAvatar(data)
        } else if (type === 'basic') {
          response = await profile.updateBasicInfo(data)
        } else {
          throw new Error('未知的更新类型')
        }

        if (response?.data?.code === 200) {
          if (type === 'avatar') {
            commit('SET_AVATAR_UPDATE_TIME', Date.now())
          }
          const { user, basic_info } = response.data.data
          if (user) {
            commit('SET_USER_INFO', user)
          }
          if (basic_info) {
            commit('SET_BASIC_INFO', basic_info)
          }
          return response
        }
        throw new Error(response?.data?.message || '更新失败')
      } catch (error) {
        console.error('Failed to update basic info:', error)
        throw error
      }
    },

    async logout({ commit }) {
      try {
        await axios.post('/api/auth/logout')
      } catch (error) {
        console.error('Logout failed:', error)
      } finally {
        // 无论是否成功登出，都清除本地状态
        localStorage.removeItem('token')
        delete axios.defaults.headers.common['Authorization']
        commit('SET_AUTHENTICATED', false)
        commit('SET_USER_INFO', null)
        router.push('/login')
      }
    },

    async fetchCompleteness({ commit }) {
      try {
        const response = await profile.getCompleteness()
        if (response.data?.code === 200) {
          commit('SET_COMPLETENESS', response.data.data)
        }
      } catch (error) {
        console.error('Failed to get completeness:', error)
      }
    },

    async login({ commit }, { tokens, user }) {
      try {
        // 1. 计算过期时间
        const now = Date.now()
        const tokenExpires = now + (24 * 60 * 60 * 1000) // token 24小时过期
        const refreshExpires = now + (7 * 24 * 60 * 60 * 1000) // refresh token 7天过期

        // 2. 保存 tokens 和过期时间到 localStorage
        localStorage.setItem(STORAGE_KEYS.TOKEN, tokens.access)
        localStorage.setItem(STORAGE_KEYS.REFRESH_TOKEN, tokens.refresh)
        localStorage.setItem(STORAGE_KEYS.USER_INFO, JSON.stringify(user))
        localStorage.setItem(STORAGE_KEYS.TOKEN_EXPIRES, tokenExpires.toString())
        localStorage.setItem(STORAGE_KEYS.REFRESH_TOKEN_EXPIRES, refreshExpires.toString())

        // 3. 更新 store 状态
        commit('SET_TOKEN', tokens.access)
        commit('SET_REFRESH_TOKEN', tokens.refresh)
        commit('SET_USER', user)
        commit('SET_LOGGED_IN', true)

        // 4. 等待一下确保状态更新完成
        await new Promise(resolve => setTimeout(resolve, 300))

        // 5. 获取用户信息
        try {
          await this.dispatch('fetchUserInfo')
        } catch (error) {
          console.warn('获取用户信息失败，但不影响登录状态:', error)
        }

        return true
      } catch (error) {
        console.error('Login error:', error)
        // 如果出错，清除所有状态
        commit('SET_TOKEN', null)
        commit('SET_REFRESH_TOKEN', null)
        commit('SET_USER', null)
        commit('SET_LOGGED_IN', false)
        localStorage.removeItem(STORAGE_KEYS.TOKEN)
        localStorage.removeItem(STORAGE_KEYS.REFRESH_TOKEN)
        localStorage.removeItem(STORAGE_KEYS.USER_INFO)
        localStorage.removeItem(STORAGE_KEYS.TOKEN_EXPIRES)
        localStorage.removeItem(STORAGE_KEYS.REFRESH_TOKEN_EXPIRES)
        throw error
      }
    },

    async refreshToken({ commit }) {
      try {
        const refreshToken = localStorage.getItem(STORAGE_KEYS.REFRESH_TOKEN)
        if (!refreshToken) {
          throw new Error('No refresh token')
        }

        const response = await auth.refreshToken({ refresh: refreshToken })

        if (response.data?.code === 200) {
          const { access } = response.data.data

          // 计算新的过期时间
          const now = Date.now()
          const tokenExpires = now + (24 * 60 * 60 * 1000)

          // 更新 store 和 localStorage
          commit('SET_TOKEN', access)
          localStorage.setItem(STORAGE_KEYS.TOKEN, access)
          localStorage.setItem(STORAGE_KEYS.TOKEN_EXPIRES, tokenExpires.toString())

          return true
        }
        return false
      } catch (error) {
        console.error('Token refresh failed:', error)
        // 清除所有认证状态
        commit('SET_TOKEN', null)
        commit('SET_REFRESH_TOKEN', null)
        commit('SET_USER', null)
        commit('SET_LOGGED_IN', false)
        localStorage.removeItem(STORAGE_KEYS.TOKEN)
        localStorage.removeItem(STORAGE_KEYS.REFRESH_TOKEN)
        localStorage.removeItem(STORAGE_KEYS.USER_INFO)
        localStorage.removeItem(STORAGE_KEYS.TOKEN_EXPIRES)
        localStorage.removeItem(STORAGE_KEYS.REFRESH_TOKEN_EXPIRES)

        return false
      }
    }
  }
})
